import { isEmptyObject, mergeJSON } from '../../../../utils/zcutils';
import { getHighlightElement, highlightLabel, highlightMarker, getListIndex } from './highlight-item-helpers';
import { getDisabledOptions } from '../../legend-event-helpers';

export function DisableItem(mouse, data) {
    let manager = this,
        { options } = manager,
        { trackerElement, config, globalFont, boxSize } = options,
        disabledOptions = getDisabledOptions(config),
        { list } = config,
        { marker: markerConfig } = list,
        { label: labelFilterConfig, marker: markerFilterConfig } = disabledOptions,
        point = getListIndex(data, options),
        highlightElement = getHighlightElement(trackerElement, point);

    if (!isEmptyObject(labelFilterConfig)) {
        let labelElement = highlightElement.selectAll('.zc-legend-legendlabel, .zc-legend-legendlabel *');
        highlightLabel(labelElement, config, globalFont, labelFilterConfig);
    }

    if (!isEmptyObject(markerFilterConfig)) {
        let mergedMarkerConfig = mergeJSON(markerFilterConfig, markerConfig),
            markerElement = highlightElement.selectAll('.zc-legend-legendfilterbox');

        highlightMarker(markerElement, boxSize, markerConfig, mergedMarkerConfig);
    }
}
